module tcp_segmentation_type(  
    input [15:0] tcp_seg_len,  
    output reg [2:0] segment_type  
);  
    always @(*) begin  
        if (tcp_seg_len <= 64)  
            segment_type = 3'b000; // Short  
        else if (tcp_seg_len > 64 && tcp_seg_len <= 128)  
            segment_type = 3'b001; // Medium  
        else  
            segment_type = 3'b010; // Long  
    end  
endmodule
